/* ────────────────────────────────────────────────────────────
   STANCE TAG
──────────────────────────────────────────────────────────── */
function StanceTag({ stance }) {
  const c = B[stance] || B.neutral;
  const MAP = { agree:"Agrees", neutral:"Neutral", disagree:"Disagrees" };
  return (
    <span style={{
      fontSize:9, padding:"3px 10px",
      background:c.bg, color:c.text,
      border:`1.5px solid ${c.border}`,
      fontWeight:800, letterSpacing:"0.1em",
      textTransform:"uppercase",
      fontFamily:"'Inter',sans-serif",
      borderRadius:1,
    }}>{MAP[stance]||"Neutral"}</span>
  );
}

/* ────────────────────────────────────────────────────────────
   API CALL
──────────────────────────────────────────────────────────── */
async function callAI(persona, topic, prompt, prev=[], material=null) {
  const prevCtx = prev.length
    ? `\n\nPrevious panelist responses — yours must NOT repeat these:\n${prev.map(r=>`• ${r.personaName}: "${r.response}"`).join("\n")}`
    : "";

  const materialCtx = material
    ? `\n\nFocus Group Material: A ${material.type} has been shared for your review. ${material.type==="image" ? "Examine the visual content carefully." : `Video title/description: "${material.name}"`} Give specific feedback on this material from your perspective.`
    : "";

  const sys = `You are roleplaying as a real individual in an NYP education focus group forum. Speak in clear, natural standard English — absolutely no Singlish or filler particles. Be distinct: introduce a fresh perspective not already raised.${material ? " Reference the shared material specifically in your feedback." : ""} Respond ONLY as valid JSON:\n{"stance":"agree"|"neutral"|"disagree","response":"3–5 sentences, first-person, unique angle","engagementLevel":1-10,"keyInsight":"one crisp sentence — your unique core argument"}`;

  const usr = `You are: ${persona.name}, ${persona.age}, ${persona.occ}
Personality: ${persona.personality}
Values: ${persona.values}
Context: ${persona.bg}

Topic: ${topic}
Question: "${prompt}"${materialCtx}${prevCtx}

Respond as ${persona.name} only. Be specific and authentic to your role.`;

  // Build message content — include image if present
  const userContent = material?.type==="image" && material?.dataUrl
    ? [
        { type:"image", source:{ type:"base64", media_type: material.mimeType||"image/jpeg", data: material.dataUrl.split(",")[1] } },
        { type:"text", text: usr }
      ]
    : usr;

  const res = await fetch("/api/chat", {
    method:"POST", headers:{"Content-Type":"application/json"},
    body: JSON.stringify({ model:"claude-sonnet-4-20250514", max_tokens:650, system:sys, messages:[{role:"user",content:userContent}] }),
  });
  if (!res.ok) throw new Error(`API ${res.status}`);
  const d = await res.json();
  const raw = d.content?.find(c=>c.type==="text")?.text || "";
  const m = raw.match(/\{[\s\S]*\}/);
  if (!m) throw new Error("JSON parse failed");
  const p = JSON.parse(m[0]);
  return {
    stance: p.stance||"neutral",
    response: p.response||"",
    engagementLevel: Math.min(10,Math.max(1,Number(p.engagementLevel)||5)),
    keyInsight: p.keyInsight||"",
  };
}

/* ────────────────────────────────────────────────────────────
   AVATAR (forum room)
──────────────────────────────────────────────────────────── */
function Avatar({ p, pos, thinking, active, selected, onClick }) {
  return (
    <button onClick={onClick} title={`${p.name} — ${p.occ}`} style={{
      position:"absolute", left:`${pos.x}%`, top:`${pos.y}%`,
      transform:"translate(-50%,-50%)", display:"flex",
      flexDirection:"column", alignItems:"center", gap:4,
      background:"none", border:"none", cursor:"pointer",
      opacity: selected ? 1 : 0.22,
      transition:"opacity .25s, transform .2s",
      zIndex:3,
    }}>
      {/* Avatar circle */}
      <div style={{
        width:46, height:46, borderRadius:"50%",
        display:"flex", alignItems:"center", justifyContent:"center",
        fontSize:20, overflow:"hidden",
        background: selected ? (thinking ? B.red : `${p.color}18`) : B.light,
        border: `2.5px solid ${selected ? (thinking ? B.red : p.color) : B.fog}`,
        boxShadow: thinking
          ? `0 0 0 4px ${B.red}30, 0 4px 20px ${B.red}40`
          : active ? `0 2px 12px ${p.color}30`
          : "none",
        animation: thinking ? "bounce .75s ease-in-out infinite" : "none",
        transition:"all .3s",
      }}>
        <img src={p.photo||DEFAULT_AVATAR_SRC} style={{ width:"100%", height:"100%", objectFit:"cover" }} alt={p.name}/>
      </div>

      {/* Thinking dots */}
      {thinking && (
        <div style={{ display:"flex", gap:3 }}>
          {[0,0.2,0.4].map((d,i)=>(
            <span key={i} style={{
              display:"block", width:4, height:4, borderRadius:"50%",
              background:B.red, animation:`dot 1.4s ${d}s ease-in-out infinite`,
            }}/>
          ))}
        </div>
      )}

      {/* Name chip */}
      <span style={{
        fontSize:9, fontWeight:800, letterSpacing:"0.04em",
        fontFamily:"'Inter',sans-serif",
        color: selected ? B.dark : B.silver,
        background: selected ? "rgba(255,255,255,0.96)" : "transparent",
        padding: selected ? "2px 7px" : "0",
        borderRadius:1,
        boxShadow: selected ? "0 1px 5px rgba(35,31,32,0.12)" : "none",
        whiteSpace:"nowrap", transition:"all .2s",
        textTransform:"uppercase",
      }}>{p.name}</span>
    </button>
  );
}

